        seg = pre.split('capital improvement projects')[-1][:200]
        if 'design' in seg:
            return 'Design'
        if 'construction' in seg:
            return 'Construction'
        if 'not started' in seg:
            return 'Not Started'
    return 'Unknown'

output = []
